# Core entity system with interfaces and abstract base class
from constants import Vector2

interface IRenderable:
    def render(self) -> str: ...

interface IUpdatable:
    def tick(self, delta: float) -> str: ...

@abstract
class GameEntity:
    entity_id: int
    position: Vector2

    def __init__(self, id: int, x: float, y: float):
        self.entity_id = id
        self.position = Vector2(x, y)

    @virtual
    def get_type(self) -> str:
        return "GameEntity"

    @abstract
    def get_stats(self) -> str: ...

class Player(GameEntity, IRenderable, IUpdatable):
    name: str
    score: int

    def __init__(self, id: int, x: float, y: float, name: str):
        super().__init__(id, x, y)
        self.name = name
        self.score = 0

    @override
    def get_type(self) -> str:
        return "Player: " + self.name

    @override
    def get_stats(self) -> str:
        return "Score: " + str(self.score)

    def render(self) -> str:
        return "[P] " + self.name + " at " + self.position.to_string()

    def tick(self, delta: float) -> str:
        self.score = self.score + int(delta * 10.0)
        return self.name + " ticked"

