# Enemy types with cross-module inheritance
from entities import GameEntity, IRenderable, IUpdatable
from constants import GameStatus

@final
class Goblin(GameEntity, IRenderable):
    aggro_range: float

    def __init__(self, id: int, x: float, y: float, range_val: float):
        super().__init__(id, x, y)
        self.aggro_range = range_val

    @override
    def get_type(self) -> str:
        return "Goblin"

    @override
    def get_stats(self) -> str:
        return "Aggro: " + str(self.aggro_range)

    def render(self) -> str:
        return "[G] Goblin"

@final
class Dragon(GameEntity, IUpdatable):
    fire_power: int

    def __init__(self, id: int, x: float, y: float, power: int):
        super().__init__(id, x, y)
        self.fire_power = power

    @override
    def get_type(self) -> str:
        return "Dragon"

    @override
    def get_stats(self) -> str:
        return "Fire: " + str(self.fire_power)

    def tick(self, delta: float) -> str:
        return "Dragon breathes fire for " + str(self.fire_power) + " damage"
